let q = false;
  const buildSearch=()=>{};
  function toast(message,tone='success',ms=TOAST_MS){const id=`t-${Date.now()}-${++toastSeq}`;state.toasts.push({id,message,tone});renderSoon();const tm=setTimeout(()=>{timers.delete(id);state.toasts=state.toasts.filter(x=>x.id!==id);renderSoon();},ms);timers.set(id,tm)}
  function clearToasts(){for(const tm of timers.values())clearTimeout(tm);timers.clear();state.toasts=[]}
  function storedProfile(){try{const s=sessionStorage.getItem(S.profile)||localStorage.getItem(S.profile);if(s){const p=JSON.parse(s);if(p?.id&&p?.name&&p?.role&&p?.department)return p}}catch{}return Ls}
  function saveProfile(p,remember){const raw=JSON.stringify(p);sessionStorage.setItem(S.profile,raw);if(remember)localStorage.setItem(S.profile,raw);else localStorage.removeItem(S.profile)}
  function clearStorage(){Object.values(S).forEach(k=>{sessionStorage.removeItem(k);localStorage.removeItem(k)});localStorage.removeItem(S.auth)}
  function allowedRoutes(){const role=(storedProfile()||Ls).role;return NAV.filter(n=>n.roles.includes(role)).map(n=>n.href)}
  function routeMeta(){return META[state.path]||META['/dashboard']}
  function showAuthNotice(notice){state.auth.notice=notice;renderSoon()}
  function closeAuthNotice(){state.auth.notice=null;renderSoon()}
  function openOtp(){state.auth.processing=false;state.auth.otpOpen=true;state.auth.form.otp='';state.auth.error='';state.auth.helper='';state.auth.otpLocked=false;state.auth.otpFailures=0;sessionStorage.setItem(S.stage,OTP_PENDING);sessionStorage.setItem(S.fail,'0');sessionStorage.removeItem(S.lock);R.innerHTML=auth();P.innerHTML='';focusModal()}
  function closeOtp(){state.auth.otpOpen=false;state.auth.form.otp='';state.auth.error='';state.auth.helper='';renderSoon()}
  function initFromStorage(){state.auth.form.userId=cleanId(sessionStorage.getItem(S.userId)||localStorage.getItem(S.userId)||'');state.auth.otpLocked=sessionStorage.getItem(S.lock)==='true';state.auth.otpFailures=Number(sessionStorage.getItem(S.fail)||'0')||0;state.auth.otpOpen=false;state.auth.processing=false;state.auth.helper='';state.auth.error='';state.auth.notice=null;state.authenticated=sessionStorage.getItem(S.auth)===AUTH_STATUS;if(!state.authenticated){sessionStorage.removeItem(S.stage);sessionStorage.removeItem(S.fail);sessionStorage.removeItem(S.lock)}if(state.authenticated)ensureShellData()}
  function ensureShellData(){if(state.shellLoaded)return;state.shellLoaded=true;Promise.all([Promise.resolve(FEEDBACK.slice().sort((a,b)=>b.createdAt.localeCompare(a.createdAt))),Promise.resolve(clone(ACCOUNTS)),Promise.resolve(clone(KNOWLEDGE_DOCS))]).then(([feedbacks,accounts,knowledge])=>{state.shell.feedbacks=feedbacks;state.shell.accounts=accounts;state.shell.knowledge=knowledge;renderSoon()})}
  function normalize(v){return String(v||'').toLowerCase().trim().replace(/\s+/g,'').replace(/[^0-9a-z가-힣]/gi,'')}
  function buildSectionHeader(title,actions='',cls='',tag='h2'){return `<div class="section-header${cls?` ${cls}`:''}"><div class="section-header__copy"><${tag} class="section-header__title">${typeof title==='string'?esc(title):title}</${tag}></div>${actions?`<div class="section-header__actions">${actions}</div>`:''}</div>`}
  function buildDetailFrame(title,body,actions='',cls='',bodyCls='',tag='h3'){return `<section class="detail-frame${cls?` ${cls}`:''}">${buildSectionHeader(title,actions,'detail-frame__header',tag)}<div class="detail-frame__body${bodyCls?` ${bodyCls}`:''}">${body}</div></section>`}
  function statusBadge(status,map){return `<span class="status-badge status-badge--${String(status).toLowerCase()}">${esc(map[status]||status)}</span>`}
  function buildToastStack(){return state.toasts.length?`<div class="toast-stack" aria-live="polite" aria-atomic="true">${state.toasts.map(t=>`<div class="toast toast--${t.tone}" role="status">${esc(t.message)}</div>`).join('')}</div>`:''}
  function shell(){const user=storedProfile();const nav=allowedRoutes().map(h=>NAV.find(n=>n.href===h)).filter(Boolean);return `<div class="admin-shell">${sidebar(user,nav)}<div class="admin-shell__main">${header(routeMeta().title,routeMeta().description)}<main class="admin-shell__content">${buildToastStack()}${contentView()}</main></div></div>${shellModals()}`}
  function sidebar(user,nav){return `<aside class="sidebar"><div class="sidebar__brand"><div class="sidebar__logo">XpERP</div><div class="sidebar__badge">AI 관리자로</div></div><nav class="sidebar__nav" aria-label="메뉴">${nav.map(i=>`<button type="button" class="sidebar__nav-item${state.path===i.href?' is-active':''}" data-nav="${i.href}" ${state.path===i.href?'aria-current="page"':''}><span class="sidebar__nav-icon" aria-hidden="true">${esc(i.key[0].toUpperCase())}</span><span>${esc(i.label)}</span></button>`).join('')}</nav><div class="sidebar__user"><div class="sidebar__user-row"><div class="sidebar__user-name">${esc(user.name)}</div><div class="sidebar__user-meta">${esc(user.id)}</div></div><div class="sidebar__user-role">${esc(user.role)} · ${esc(user.department)}</div><button type="button" class="secondary-button sidebar__logout" data-action="logout-open">로그아웃</button></div></aside>`}
  function header(title,desc){return `<header class="top-header"><div class="top-header__copy"><h1 class="top-header__title">${esc(title)}</h1><p class="top-header__description">${esc(desc)}</p></div></header>`}
  function auth(){return `<main class="auth-shell auth-shell--standalone"><section class="auth-card auth-standalone"><div class="auth-card__intro auth-standalone__intro"><span class="auth-card__badge">Xp도우미</span><h1 class="auth-card__title">Xp도우미 관리자</h1><p class="auth-card__eyebrow">관리자 전용 시스템</p><p class="auth-card__description">본 시스템은 내부 관리자 전용입니다.<br>무단 접근 및 정보 열람 시 관련 법령에 따라 책임이 발생할 수 있습니다.</p></div><form class="auth-form" data-form="login"><div class="auth-form__header"><h2 class="auth-form__title">관리자 로그인</h2><p class="auth-form__caption">승인된 계정만 접속 가능합니다.</p></div><div class="auth-form__fields"><label class="field auth-field"><span class="field__label">아이디</span><input class="field__input auth-input" maxLength="10" value="${esc(state.auth.form.userId)}" placeholder="예: admin01" data-field="userId"></label><label class="field auth-field"><span class="field__label">비밀번호</span><input type="password" class="field__input auth-input" maxLength="12" value="${esc(state.auth.form.password)}" placeholder="비밀번호 입력" data-field="password"></label><label class="auth-remember"><input type="checkbox" ${state.auth.remember?'checked':''} data-field="remember"><span>아이디 저장</span></label></div><div class="auth-form__actions"><button type="submit" class="primary-button auth-submit" ${state.auth.processing?'disabled':''}>${state.auth.processing?'처리 중...':'로그인'}</button></div><div class="auth-form__feedback" aria-live="polite">${state.auth.error?`<p class="auth-error">${esc(state.auth.error)}</p>`:''}${!state.auth.error&&state.auth.helper?`<p class="auth-helper">${esc(state.auth.helper)}</p>`:''}</div></form></section></main>${authModals()}`}
  function authModals(){let html='';if(state.auth.otpOpen)html+=`<div class="modal-backdrop auth-otp-backdrop"><section class="modal auth-otp-modal" role="dialog" aria-modal="true" aria-label="OTP 인증" data-modal="otp"><div class="modal__header auth-otp-modal__header"><div><h3>OTP 인증</h3><p class="auth-otp-modal__caption">${esc(state.auth.helper||'OTP를 입력하면 로그인 절차를 완료합니다.')}</p></div></div><form class="auth-otp-modal__body" data-form="otp"><label class="field auth-otp-field"><span class="field__label">OTP</span><input class="field__input auth-input auth-input--otp" value="${esc(state.auth.form.otp)}" maxLength="6" placeholder="6자리 OTP 입력" data-field="otp" ${state.auth.processing?'disabled':''}></label><div class="auth-form__feedback" aria-live="polite">${state.auth.error?`<p class="auth-error">${esc(state.auth.error)}</p>`:''}${!state.auth.error&&state.auth.helper?`<p class="auth-helper">${esc(state.auth.helper)}</p>`:''}</div><div class="auth-form__actions auth-otp-modal__actions"><button type="button" class="secondary-button auth-cancel" data-action="otp-close">취소</button><button type="submit" class="primary-button auth-submit" ${state.auth.processing||cleanOtp(state.auth.form.otp).length!==6?'disabled':''}>${state.auth.processing?'처리 중...':'인증 완료'}</button></div></form></section></div>`;if(state.auth.notice)html+=`<div class="modal-backdrop auth-notice-backdrop"><section class="modal modal--sm modal--compact auth-notice-modal" role="dialog" aria-modal="true" aria-label="${esc(state.auth.notice.title)}" data-modal="notice"><div class="modal__header modal__header--tight auth-notice-modal__header"><div><h3>${esc(state.auth.notice.title)}</h3></div></div><div class="modal__body auth-notice-modal__body"><p class="auth-notice-modal__message">${esc(state.auth.notice.message)}</p></div><div class="modal__footer modal__footer--split"><button type="button" class="primary-button" data-action="notice-ok">확인</button></div></section></div>`;return html}
  function shellModals(){let html='';if(state.logoutOpen)html+=`<section class="modal modal--sm modal--compact" role="dialog" aria-modal="true" aria-label="로그아웃 확인" data-modal="logout"><div class="modal__header modal__header--tight"><div><h3>로그아웃</h3></div></div><div class="modal__body"><p class="logout-confirm__text">로그아웃 하시겠습니까?</p></div><div class="modal__footer modal__footer--split"><button type="button" class="secondary-button" data-action="logout-cancel">취소</button><button type="button" class="danger-button" data-action="logout-confirm">확인</button></div></section>`;if(state.content.modalOpen)html+=contentModal();if(state.content.deleteOpen)html+=`<section class="modal modal--sm modal--compact" role="dialog" aria-modal="true" aria-label="문서 삭제 확인" data-modal="content-delete"><div class="modal__header modal__header--tight"><div><h3>문서 삭제 확인</h3></div></div><div class="modal__body"><p class="content-confirm">문서를 삭제하면 목록에서 사라집니다. 복구 작업은 별도로 제공되지 않습니다.</p></div><div class="modal__footer modal__footer--split"><button type="button" class="secondary-button" data-action="content-delete-cancel">취소</button><button type="button" class="danger-button" data-action="content-delete-confirm">삭제</button></div></section>`;if(state.cache.modalOpen)html+=cacheModal();if(state.cache.deleteOpen)html+=`<section class="modal modal--sm modal--compact" role="dialog" aria-modal="true" aria-label="캐시 답변 삭제 확인" data-modal="cache-delete"><div class="modal__header modal__header--tight"><div><h3>캐시 답변 삭제 확인</h3></div></div><div class="modal__body"><p class="content-confirm">선택한 답변을 삭제하면 캐시 답변에서 즉시 제외됩니다.</p></div><div class="modal__footer modal__footer--split"><button type="button" class="secondary-button" data-action="cache-delete-cancel">취소</button><button type="button" class="danger-button" data-action="cache-delete-confirm">삭제</button></div></section>`;if(state.accounts.actionModal)html+=accountActionModal();if(state.accounts.addOpen)html+=accountAddModal();return html}
  function loading(label){return `<section class="panel panel--main"><div class="content-empty content-empty--detail">${esc(label)} 데이터를 불러오는 중입니다.</div></section>`}
  function dashboard(){const sec=D[state.dash.range];return `<div class="dashboard-grid"><section class="panel panel--main">${buildSectionHeader('기간별 지표 현황',`<div class="dashboard-header-actions">${['DAY','WEEK','MONTH'].map(r=>`<button type="button" class="time-range-tabs__button${state.dash.range===r?' is-selected':''}" data-action="dash-range" data-value="${r}">${r==='DAY'?'일간':r==='WEEK'?'주간':'월간'}</button>`).join('')}</div>`,'','h2')}<div class="metric-card-grid">${sec.metrics.map(m=>`<article class="metric-card"><div class="metric-card__label">${esc(m.label)}</div><div class="metric-card__value">${m.value.toLocaleString()}건</div><div class="metric-card__compare ${m.compareDirection==='UP'?'is-up':'is-down'}"><strong>${m.compareDirection==='UP'?'+':'-'} ${m.compareRate}%</strong><span>${esc(m.compareLabel)}</span></div></article>`).join('')}</div>${trendChart(sec.trend)}</section><section class="dashboard-side">${keywordList('질문 키워드',sec.fixedKeywords)}${feedbackRatio(sec.fixedFeedbackRatio)}</section></div>`}
  function keywordList(title,items,bare=false){return `<section class="dashboard-keyword-card${bare?' dashboard-keyword-card--bare':''}">${buildSectionHeader(title,'','dashboard-keyword-card__header')}<ol class="keyword-list">${items.map(i=>`<li class="keyword-list__item"><div class="keyword-list__left"><span class="keyword-list__rank">${i.rank}</span><span class="keyword-list__label">${esc(i.label)}</span></div><div class="keyword-list__stats"><strong class="keyword-list__count">${i.count.toLocaleString()}건</strong><span class="keyword-list__divider">·</span><span class="keyword-list__ratio">${ratio(i.ratio)}</span></div></li>`).join('')}</ol></section>`}
  function trendChart(points){const max=Math.max(...points.map(p=>Math.max(p.visitors,p.inquiries)),1);const plotted=points.map((p,i)=>({ ...p, x:32+(i*(760-64))/Math.max(points.length-1,1), vy:340-32-(p.visitors/max)*(340-64), iy:340-32-(p.inquiries/max)*(340-64) }));const line=plotted.map((p,i)=>`${i===0?'M':'L'} ${p.x} ${p.iy}`).join(' ');return `<div class="trend-chart"><div class="trend-chart__stage"><svg viewBox="0 0 760 340" class="trend-chart__svg" role="img">${[0,1,2,3,4].map(i=>{const y=32+(i*(340-64))/4;return `<line x1="32" y1="${y}" x2="728" y2="${y}" class="trend-chart__grid"></line>`}).join('')}${plotted.map((p,i)=>`<g class="trend-chart__bar-group" data-trend="${i}"><path d="M ${p.x-12} ${p.vy+Math.max(340-32-p.vy,0)} H ${p.x+12} V ${p.vy} H ${p.x-12} Z" class="trend-chart__bar"></path><rect x="${p.x-16}" y="${p.vy}" width="32" height="${340-32-p.vy}" fill="transparent" class="trend-chart__bar-hitarea"></rect><text x="${p.x}" y="332" text-anchor="middle" class="trend-chart__label">${esc(p.label)}</text></g>`).join('')}<path d="${line}" class="trend-chart__path"></path>${plotted.map((p,i)=>`<g class="trend-chart__point-group" data-trend="${i}"><circle cx="${p.x}" cy="${p.iy}" r="5" class="trend-chart__point"></circle><circle cx="${p.x}" cy="${p.iy}" r="10" fill="transparent"></circle></g>`).join('')}</svg>${state.dash.hoveredTrend!=null?`<div class="trend-chart__tooltip" aria-live="polite" style="left:${state.dash.tooltip.left}px;top:${state.dash.tooltip.top}px;"><span class="trend-chart__tooltip-date">${esc(plotted[state.dash.hoveredTrend].dateLabel)}</span><strong>${plotted[state.dash.hoveredTrend].visitors.toLocaleString()} 접속자</strong><span>${plotted[state.dash.hoveredTrend].inquiries.toLocaleString()} 문의</span></div>`:''}</div><div class="trend-chart__legend"><span class="trend-chart__legend-item"><span class="trend-chart__legend-dot trend-chart__legend-dot--bar"></span><span>접속자 수</span></span><span class="trend-chart__legend-item"><span class="trend-chart__legend-dot"></span><span>문의 수</span></span></div></div>`}
  function feedbackRatio(data){const pos=(data.positive.count/data.totalCount)*100,neg=(data.negative.count/data.totalCount)*100;const title=`${state.dash.selectedReaction==='NEGATIVE'?'아쉬워요':'만족해요'} TOP5 키워드`;const slice=(start,end,outer=42,inner=24)=>{const p=(r,a)=>{const rad=((a-90)*Math.PI)/180;return{x:50+r*Math.cos(rad),y:50+r*Math.sin(rad)}};const s=p(outer,start),e=p(outer,end),i=p(inner,end),j=p(inner,start),large=end-start<=180?0:1;return`M ${s.x.toFixed(3)} ${s.y.toFixed(3)} A ${outer} ${outer} 0 ${large} 0 ${e.x.toFixed(3)} ${e.y.toFixed(3)} L ${i.x.toFixed(3)} ${i.y.toFixed(3)} A ${inner} ${inner} 0 ${large} 1 ${j.x.toFixed(3)} ${j.y.toFixed(3)} Z`};return `<section class="panel panel--side feedback-ratio-card">${buildSectionHeader('피드백 비율','','feedback-ratio-card__header')}<div class="feedback-ratio"><div class="feedback-ratio__chart-shell"><svg class="feedback-ratio__chart" viewBox="0 0 100 100" role="img" aria-label="피드백 비율 도넛 차트. 만족해요 ${ratio(pos)}, 아쉬워요 ${ratio(neg)}"><path d="${slice(0,pos*3.6)}" class="feedback-ratio__slice feedback-ratio__slice--positive" data-reaction="POSITIVE" tabindex="0"></path><path d="${slice(pos*3.6,360)}" class="feedback-ratio__slice feedback-ratio__slice--negative" data-reaction="NEGATIVE" tabindex="0"></path><circle cx="50" cy="50" r="24" class="feedback-ratio__hole"></circle><text x="50" y="46" text-anchor="middle" class="feedback-ratio__center-label">전체 건수</text><text x="50" y="60" text-anchor="middle" class="feedback-ratio__center-value">${data.totalCount.toLocaleString()}건</text></svg>${state.dash.hoveredReaction?`<div class="feedback-ratio__tooltip" aria-live="polite"><span class="feedback-ratio__tooltip-label">${esc(state.dash.hoveredReaction==='POSITIVE'?'만족해요':'아쉬워요')}</span><strong>${(state.dash.hoveredReaction==='POSITIVE'?data.positive.count:data.negative.count).toLocaleString()}건 · ${ratio((state.dash.hoveredReaction==='POSITIVE'?data.positive.count:data.negative.count)/data.totalCount*100)}</strong></div>`:''}</div><div class="feedback-toggle" role="tablist" aria-label="피드백 유형">${['POSITIVE','NEGATIVE'].map(r=>`<button type="button" role="tab" aria-selected="${state.dash.selectedReaction===r}" class="feedback-toggle__button${state.dash.selectedReaction===r?' is-selected':''}" data-action="dash-reaction" data-value="${r}">${r==='POSITIVE'?'만족해요':'아쉬워요'}</button>`).join('')}</div>${keywordList(title,state.dash.selectedReaction==='POSITIVE'?data.positive.keywords:data.negative.keywords,true)}</div></section>`}
  function contentPage(){const list=contentFiltered();const selected=list.find(x=>x.id===state.content.selectedId)||list[0]||null;return `<div class="page-content page-content--fill content-page"><div class="content-grid"><section class="content-table-card">${buildSectionHeader('문서 목록',`<button type="button" class="primary-button" data-action="content-open-create">문서 업로드</button>`,'content-table-card__header content-table-card__header--list')}<form class="content-toolbar content-toolbar--content content-table-card__toolbar" data-form="content-filter"><label class="field content-toolbar__field content-toolbar__field--select"><span class="field__label">문서 유형</span><select class="field__input" data-field="content-type">${CONTENT_TYPE.map(o=>`<option value="${o.value}"${state.content.type===o.value?' selected':''}>${o.label}</option>`).join('')}</select></label><label class="field content-toolbar__field content-toolbar__field--search"><span class="field__label">문서명 검색</span><input class="field__input" type="search" value="${esc(state.content.filterDraft)}" placeholder="2자 이상 입력" data-field="content-filterDraft"></label><div class="content-toolbar__actions"><button type="submit" class="primary-button content-toolbar__button">검색</button><button type="button" class="secondary-button content-toolbar__button" data-action="content-reset-filter">초기화</button></div></form><div class="content-table-scroll"><table class="content-table"><thead><tr><th>문서명</th><th>유형</th><th>등록자</th><th>등록일</th><th>수정일</th><th>상태</th></tr></thead><tbody>${list.length===0?`<tr><td colSpan="6" class="content-empty">조건에 맞는 문서가 없습니다.</td></tr>`:list.map(d=>`<tr class="${selected&&d.id===selected.id?'is-selected':''}" data-content-select="${d.id}"><td><div class="content-table__title">${esc(d.name)}</div><div class="content-table__sub">${esc(d.path)}</div></td><td>${d.type==='MANUAL'?'매뉴얼':'FAQ'}</td><td>${esc(d.author)}</td><td>${esc(d.createdAt)}</td><td>${esc(d.updatedAt)}</td><td>${statusBadge(d.status,CONTENT_LABEL)}</td></tr>`).join('')}</tbody></table></div></section>${contentDetail(selected)}</div>${state.content.modalOpen?contentModal():''}${state.content.deleteOpen?contentDeleteModal():''}</div>`}
  function contentFiltered(){const k=state.content.filterApplied.trim().toLowerCase();return state.content.docs.filter(d=>(!k||d.name.toLowerCase().includes(k)||d.path.toLowerCase().includes(k))&&(state.content.type==='ALL'||d.type===state.content.type)).sort((a,b)=>b.updatedAt.localeCompare(a.updatedAt)||b.createdAt.localeCompare(a.createdAt))}
