  function contentModal(){return `<section class="modal modal--lg" role="dialog" aria-modal="true" aria-label="${esc(state.content.modalMode==='EDIT'?'문서 수정 업로드':'문서 업로드')}" data-modal="content"><div class="modal__header"><div><h3>${esc(state.content.modalMode==='EDIT'?'문서 수정 업로드':'문서 업로드')}</h3></div></div><div class="modal__body"><label class="field"><span class="field__label">파일 선택 *</span><input class="field__input" type="file" accept=".pdf,.docx,.txt,.md" data-field="content-file"><span class="content-file-name">${state.content.selectedFileLabel?`선택한 파일: ${esc(state.content.selectedFileLabel)}`:'파일을 선택해 주세요.'}</span></label><label class="field"><span class="field__label">저장 경로</span><input class="field__input" value="${esc(state.content.form.path)}" placeholder="/rag/manual/chatbot-guide" data-field="content-path"></label><label class="field"><span class="field__label">문서 유형</span><select class="field__input" data-field="content-modalType"><option value="MANUAL"${state.content.form.type==='MANUAL'?' selected':''}>매뉴얼</option><option value="FAQ"${state.content.form.type==='FAQ'?' selected':''}>FAQ</option></select></label>${state.content.modalError?`<p class="content-error">${esc(state.content.modalError)}</p>`:''}</div><div class="modal__footer modal__footer--split"><button type="button" class="secondary-button" data-action="content-close">취소</button><button type="button" class="primary-button" data-action="content-save">${state.content.modalMode==='EDIT'?'수정 저장':'저장'}</button></div></section>`}
