  function cachePage(){const list=cacheFiltered(),pages=Math.max(1,Math.ceil(list.length/10)),page=Math.min(Math.max(state.cache.page,1),pages),slice=list.slice((page-1)*10,page*10),selected=list.find(x=>x.id===state.cache.selectedId)||list[0]||null;return `<div class="cache-qa-layout">${buildToastStack()}<div class="cache-qa-grid">${listPanel('캐시 답변 목록',`<button type="button" class="primary-button" data-action="cache-open-create">캐시 답변 등록</button>`,`<form class="cache-qa-toolbar" data-form="cache-filter"><label class="field cache-qa-field"><span class="field__label">질문 검색</span><input class="field__input" type="search" placeholder="2자 이상 입력 권장" value="${esc(state.cache.filterDraft)}" data-field="cache-filterDraft"></label><label class="field cache-qa-field"><span class="field__label">상태</span><select class="field__input" data-field="cache-status">${CACHE_FILTER.map(o=>`<option value="${o.value}"${state.cache.status===o.value?' selected':''}>${o.label}</option>`).join('')}</select></label><div class="cache-qa-toolbar__actions"><button type="submit" class="primary-button">검색</button><button type="button" class="secondary-button" data-action="cache-reset-filter">초기화</button></div></form>`,`<div class="list-panel__scroll cache-qa-list-scroll">${slice.length===0?`<div class="list-panel__empty">조건에 맞는 답변이 없습니다.</div>`:`<table class="content-table cache-qa-table"><thead><tr><th>질문</th><th>상태</th><th>등록일</th><th>수정일</th></tr></thead><tbody>${slice.map(i=>`<tr class="${selected&&i.id===selected.id?'is-selected':''}" data-cache-select="${i.id}"><td><div class="content-table__title">${esc(i.question)}</div></td><td>${statusBadge(i.status,CACHE_LABEL)}</td><td>${esc(i.createdAt)}</td><td>${esc(i.updatedAt)}</td></tr>`).join('')}</tbody></table>`}</div>`,pagination(page,pages),'cache-qa-list-card')}${cacheDetail(selected)}</div>${state.cache.modalOpen?cacheModal():''}${state.cache.deleteOpen?cacheDeleteModal():''}</div>`}
  function cacheFiltered(){const k=norm(state.cache.filterApplied);return state.cache.items.map(item=>{const q=norm(item.question);const exact=!k||q.includes(k)||k.includes(q);const score=!k?1:Math.max(q===k?1:1-Math.abs(q.length-k.length)/Math.max(q.length,k.length,1),q.includes(k)?0.92:0,k.includes(q)?0.92:0);return{item,score,exact}}).filter(({item,score,exact})=>(state.cache.status==='ALL'||item.status===state.cache.status)&&(!k||exact||score>=0.35)).sort((a,b)=>k&&b.score!==a.score?b.score-a.score:cmpDesc(a.item.createdAt,b.item.createdAt)).map(x=>x.item)}
  function cacheDetail(i){if(!i)return buildDetailFrame('상세 정보',`<div class="list-panel__empty cache-qa-empty">답변을 선택하면 상세 정보가 표시됩니다.</div>`,'','cache-qa-detail-card');return buildDetailFrame('상세 정보',`<div class="cache-qa-detail-scroll"><div class="feedback-conversation-section"><p class="feedback-conversation-label">대화 내용</p><div class="cache-qa-conversation"><div class="feedback-conversation__turn feedback-conversation__turn--user"><p class="feedback-conversation__speaker">질문</p><p class="feedback-conversation__message">${esc(i.question)}</p></div><div class="feedback-conversation__turn feedback-conversation__turn--bot"><p class="feedback-conversation__speaker">답변</p><p class="feedback-conversation__message">${esc(i.answer)}</p></div></div></div><dl class="content-detail__list cache-qa-meta"><div><dt>등록자</dt><dd>${esc(i.createdBy)}</dd></div><div><dt>등록일</dt><dd>${esc(i.createdAt)}</dd></div><div><dt>수정자</dt><dd>${esc(i.updatedBy)}</dd></div><div><dt>수정일</dt><dd>${esc(i.updatedAt)}</dd></div><div><dt>캐시 조회 수</dt><dd>${i.hitCount.toLocaleString()}</dd></div></dl><div class="cache-qa-detail-actions"><button type="button" class="secondary-button" data-action="cache-open-edit">수정</button><button type="button" class="primary-button" data-action="cache-toggle">${i.status==='ACTIVE'?'비활성화':'활성화'}</button><button type="button" class="danger-button" data-action="cache-open-delete">삭제</button></div></div>`,statusBadge(i.status,CACHE_LABEL),'cache-qa-detail-card')}
  function cacheModal(){return `<section class="modal modal--xl" role="dialog" aria-modal="true" aria-label="${esc(state.cache.modalMode==='EDIT'?'캐시 답변 수정':'캐시 답변 등록')}" data-modal="cache"><div class="modal__header"><div><h3>${esc(state.cache.modalMode==='EDIT'?'캐시 답변 수정':'캐시 답변 등록')}</h3></div></div><div class="modal__body"><div class="cache-qa-form cache-qa-form--modal"><label class="field"><span class="field__label">질문 *</span><textarea class="field__input knowledge-textarea cache-qa-textarea" rows="3" maxLength="500" placeholder="캐시 답변용 질문을 입력해 주세요." data-field="cache-question">${esc(state.cache.form.question)}</textarea><p class="cache-qa-form__counter">${state.cache.form.question.length}/500자</p></label><label class="field"><span class="field__label">답변 *</span><textarea class="field__input knowledge-textarea cache-qa-textarea" rows="6" maxLength="2000" placeholder="캐시 답변으로 반환할 답변을 입력해 주세요." data-field="cache-answer">${esc(state.cache.form.answer)}</textarea><p class="cache-qa-form__counter">${state.cache.form.answer.length}/2000자</p></label><label class="field"><span class="field__label">상태</span><select class="field__input" data-field="cache-modalStatus"><option value="ACTIVE"${state.cache.form.status==='ACTIVE'?' selected':''}>활성</option><option value="INACTIVE"${state.cache.form.status==='INACTIVE'?' selected':''}>비활성</option></select></label>${state.cache.modalError?`<p class="content-error">${esc(state.cache.modalError)}</p>`:''}</div></div><div class="modal__footer modal__footer--split"><button type="button" class="secondary-button" data-action="cache-reset-modal">초기화</button><button type="button" class="primary-button" data-action="cache-save">${state.cache.modalMode==='EDIT'?'수정 저장':'등록'}</button></div></section>`}
  function cacheDeleteModal(){return `<section class="modal modal--sm modal--compact" role="dialog" aria-modal="true" aria-label="캐시 답변 삭제 확인" data-modal="cache-delete"><div class="modal__header modal__header--tight"><div><h3>캐시 답변 삭제 확인</h3></div></div><div class="modal__body"><p class="content-confirm">선택한 답변을 삭제하면 캐시 답변에서 즉시 제외됩니다.</p></div><div class="modal__footer modal__footer--split"><button type="button" class="secondary-button" data-action="cache-delete-cancel">취소</button><button type="button" class="danger-button" data-action="cache-delete-confirm">삭제</button></div></section>`}
  function listPanel(title,actions,toolbar,body,footer='',cls=''){return `<section class="list-panel${cls?` ${cls}`:''}">${buildSectionHeader(title,actions,'list-panel__header')}${toolbar?`<div class="list-panel__toolbar">${toolbar}</div>`:''}<div class="list-panel__body">${body}</div>${footer?`<div class="list-panel__footer">${footer}</div>`:''}</section>`}
  function pagination(page,total){const items=pageNums(page,total);return `<nav class="pagination" aria-label="페이지네이션"><button type="button" class="pagination__button" data-action="cache-page" data-value="${page-1}" ${page===1?'disabled':''}>이전</button>${items.map(i=>i===null?`<span class="pagination__ellipsis" aria-hidden="true">...</span>`:`<button type="button" class="pagination__button${page===i?' is-active':''}" data-action="cache-page" data-value="${i}" ${page===i?'aria-current="page"':''}>${i}</button>`).join('')}<button type="button" class="pagination__button" data-action="cache-page" data-value="${page+1}" ${page===total?'disabled':''}>다음</button></nav>`}
  function pageNums(page,total){if(total<=7)return Array.from({length:total},(_,i)=>i+1);const arr=[1];if(page>4)arr.push(null);const start=Math.max(2,page-1),end=Math.min(total-1,page+1);for(let i=start;i<=end;i++)arr.push(i);if(page<total-3)arr.push(null);arr.push(total);return arr}
  function knowledgePage(){const docs=state.shell.knowledge||[];const docsFiltered=state.knowledge.form.documentType?docs.filter(d=>d.type===state.knowledge.form.documentType):docs;return `<div class="knowledge-layout"><div class="knowledge-grid"><section class="panel panel--main">${buildSectionHeader('조회 조건')}<div class="knowledge-form"><label class="field"><span class="field__label">문서 유형 *</span><select class="field__input" data-field="knowledge-type"><option value="">선택하세요</option><option value="MANUAL"${state.knowledge.form.documentType==='MANUAL'?' selected':''}>매뉴얼</option><option value="FAQ"${state.knowledge.form.documentType==='FAQ'?' selected':''}>FAQ</option></select></label><label class="field"><span class="field__label">테스트 문서 *</span><select class="field__input" data-field="knowledge-doc" ${!state.knowledge.form.documentType?'disabled':''}><option value="">선택하세요</option>${docsFiltered.map(d=>`<option value="${d.id}"${state.knowledge.form.documentId===d.id?' selected':''}>${esc(d.name)}</option>`).join('')}</select></label><label class="field"><span class="field__label">질문 입력 *</span><textarea class="field__input knowledge-textarea" rows="4" maxLength="1000" placeholder="1자 이상 입력 (최대 1000자)" data-field="knowledge-question">${esc(state.knowledge.form.question)}</textarea></label><div class="knowledge-action-row"><button type="button" class="secondary-button" data-action="knowledge-reset" ${state.knowledge.status==='IDLE'&&!state.knowledge.result?'disabled':''}>초기화</button><button type="button" class="primary-button" data-action="knowledge-query" ${!canQuery()||state.knowledge.status==='LOADING'?'disabled':''}>${state.knowledge.status==='LOADING'?'조회 중':'조회'}</button><button type="button" class="secondary-button" data-action="knowledge-error">오류 보기</button></div></div></section>${buildDetailFrame('조회 결과',knowledgeResult(),'','panel panel--main')}</div></div>`}
